(68, 'Philips 55PUS8508 4K Ultra HD 55', '99482df2-2088-40f8-82e0-180b1971b43a_size780x780_quality60_cropCenter.jpg', '99482df2-2088-40f8-82e0-180b1971b43a_size780x780_quality60_cropCenter.jpg', '99482df2-2088-40f8-82e0-180b1971b43a_size780x780_quality60_cropCenter.jpg', '99482df2-2088-40f8-82e0-180b1971b43a_size780x780_quality60_cropCenter.jpg', 'philips-55pus8508-4k-ultra-hd-55&quot;-140-ekran-uydu-alicili-google-smart-led-tv', 16699, '<p style=\"text-align: left;\"><strong>Philips 55PUS8508 4K Ultra HD 55\" 140 Ekran Uydu Alıcılı Google Smart LED TV</strong></p>\r\n<table>\r\n<tbody>\r\n<tr>\r\n<td><strong>&Uuml;r&uuml;n &Ouml;zellikleri</strong></td>\r\n<td><strong>A&ccedil;ıklama</strong></td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>AB Yeni Enerji Sınıfı</strong></p>\r\n</td>\r\n<td>\r\n<p>F</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>Boyutlar</strong></p>\r\n</td>\r\n<td>\r\n<p><a href=\"tel:1231-722-82\">1231-722-82</a> mm</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>Bluetooth</strong></p>\r\n</td>\r\n<td>\r\n<p>Var</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>WiFi</strong></p>\r\n</td>\r\n<td>\r\n<p>Var</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>&Ccedil;&ouml;z&uuml;n&uuml;rl&uuml;k (Piksel)</strong></p>\r\n</td>\r\n<td>\r\n<p>3840 x 2160</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>&Ccedil;&ouml;z&uuml;n&uuml;rl&uuml;k</strong></p>\r\n</td>\r\n<td>\r\n<p>4K</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>Dahili Uydu Alıcısı</strong></p>\r\n</td>\r\n<td>\r\n<p>Var</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>Ekran Ebatı (in&ccedil;/cm)</strong></p>\r\n</td>\r\n<td>\r\n<p>139 cm</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>Ethernet</strong></p>\r\n</td>\r\n<td>\r\n<p>Var</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>HDMI Girişleri</strong></p>\r\n</td>\r\n<td>\r\n<p>4</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>USB Girişleri</strong></p>\r\n</td>\r\n<td>\r\n<p>2</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>Model Yılı</strong></p>\r\n</td>\r\n<td>\r\n<p>2023</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>Smart TV</strong></p>\r\n</td>\r\n<td>\r\n<p>Var</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>Tuner</strong></p>\r\n</td>\r\n<td>\r\n<p>Var</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>4K İ&ccedil;erik Uygulamaları</strong></p>\r\n</td>\r\n<td>\r\n<p>Youtube -Amazon prime-Netflix</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>Garanti S&uuml;resi</strong></p>\r\n</td>\r\n<td>\r\n<p>24 ay garantili</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td>\r\n<p><strong>Kurulum</strong></p>\r\n</td>\r\n<td>\r\n<p>&Uuml;r&uuml;n&uuml;n garantisinin başlayabilmesi i&ccedil;in bu &uuml;r&uuml;n&uuml;n kutusu yetkili servis tarafından a&ccedil;ılmalı, kurulum yetkili servis tarafından yapılmalıdır.</p>\r\n<p><strong>Yetkili Servis Adı:&nbsp;</strong>PHILIPS Servis</p>\r\n<p><strong>Yetkili Servis İletişim Bilgisi:&nbsp;</strong><a href=\"tel:0850 222 44 66\">0850 222 44 66</a></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>&Uuml;retim Yeri: T&uuml;rkiye</p>\r\n<p>İnternet sitemizde ve online satış kanallarımızda yer alan &uuml;r&uuml;n etiket bilgileri, &uuml;r&uuml;n&uuml;n tedarik&ccedil;isi tarafından A101 Yeni Mağazacılık A.Ş &lsquo;ye iletilen en g&uuml;ncel bilgilerdir. &Uuml;r&uuml;n etiket bilgileri ile internet sitemiz ve online satış kanallarımızda bulunan bilgiler arasında herhangi bir farklılık bulunması halinde sorumluluk tamamen tedarik&ccedil;i firmaya aittir.</p>\r\n<p>Fiyatlarımız; a101.com.tr, A101 Kapıda uygulaması ve mağazalarımızda farklılık g&ouml;sterebilir, belirtilen &uuml;r&uuml;n fiyatı yalnızca bu satış kanalı i&ccedil;in ge&ccedil;erlidir.</p>\r\n<p>&Uuml;r&uuml;nlerimiz, yukarıda belirtilen satış kanallarında satışa sunulmaktadır. Online satış kanalı, a101.com.tr website, mobil ve A101 uygulamasını kapsamaktadır.</p>\r\n<p>Mesafeli Satış S&ouml;zleşmemiz uyarınca; toptan veya yeniden satış ama&ccedil;lı oluşturulduğu tespit edilen siparişler ile &uuml;r&uuml;n, hizmet ve indirimlerimizden t&uuml;m m&uuml;şterilerimizin faydalanabilmesi ve stok&ccedil;uluğun engellenmesi i&ccedil;in 1 adetin &uuml;zerindeki doğrudan ve dolaylı siparişleri A101&rsquo;in iptal hakkı saklıdır.</p>', 'Philips', 26041785),
(69, 'Philips 43PUS7607 43\'\' UHD Smart LED TV', 'b61f8842-5859-40d8-acee-edecf88bc2b4_size780x780_quality60_cropCenter.jpg', 'e0e87426-6439-4a3c-bb9b-45c0d4ebf3ad_size780x780_quality60_cropCenter.jpg', '9f497d5f-032b-463f-abdd-66e568464dbf_size780x780_quality60_cropCenter.jpg', 'b61f8842-5859-40d8-acee-edecf88bc2b4_size780x780_quality60_cropCenter.jpg', 'philips-43pus7607-43\'\'-uhd-smart-led-tv', 6199, '<p><strong>Philips 43PUS7607 43\'\' UHD Smart LED TV</strong></p>\r\n<p>Bu uygun fiyatlı akıllı TV ile istediğiniz g&ouml;r&uuml;nt&uuml; ve ses kalitesini elde edin. Net ve canlı filmler ile programların yanı sıra harika g&ouml;r&uuml;nen ve akıcı oyun i&ccedil;eriklerinin keyfini &ccedil;ıkarın. Premium&nbsp;&nbsp;Dolby Atmos ses sayesinde m&uuml;zik i&ccedil;eriklerini en iyi şekilde deneyimleyin.</p>\r\n<p><strong>&Uuml;st&uuml;n değer - &Uuml;st&uuml;n performans</strong><br>Canlı g&ouml;r&uuml;nt&uuml; Philips 4K UHD LED TV</p>\r\n<p>Sinematik g&ouml;r&uuml;nt&uuml; ve ses. Dolby Vision ve Dolby Atmos</p>\r\n<p>Net HDR g&ouml;r&uuml;nt&uuml;. Philips 4K UHD TV</p>\r\n<p><strong>İnce tasarım - &Ccedil;evreye duyarlı ambalaj</strong></p>\r\n<p>İnce, &ccedil;ekici tasarım</p>\r\n<p>İnce TV gelecek i&ccedil;in &uuml;retildi</p>\r\n<p><strong>Akıllı - Eğlenceli - Kontrol&uuml; kolay</strong></p>\r\n<p>Oyun oynamak i&ccedil;in harika</p>\r\n<p>T&uuml;m konsollarda d&uuml;ș&uuml;k gecikme s&uuml;resi</p>\r\n<p>SAPHI. TV\'nizin keyfini &ccedil;ıkarmanın akıllı yolu</p>\r\n<p><strong>Teknik &Ouml;zellikler</strong></p>\r\n<p><strong>G&ouml;r&uuml;nt&uuml;/Ekran</strong></p>\r\n<p><strong>Ekran:&nbsp;</strong>4K Ultra HD LED</p>\r\n<p><strong>&Ccedil;apraz ekran boyutu (metrik):&nbsp;</strong>108 cm</p>\r\n<p><strong>Ekran &ccedil;&ouml;z&uuml;n&uuml;rl&uuml;ğ&uuml;:&nbsp;</strong>3840 x 2160</p>\r\n<p><strong>Yerel yenileme hızı:&nbsp;</strong>60 Hz</p>\r\n<p><strong>Fotoğraf motoru:&nbsp;</strong>Pixel Precise Ultra HD</p>\r\n<p><strong>G&ouml;r&uuml;nt&uuml; geliștirme:&nbsp;</strong>Dolby Vision, HLG (HybridLog Gamma), HDR10+ uyumlu</p>\r\n<p><strong>Desteklenen Ekran &Ccedil;&ouml;z&uuml;n&uuml;rl&uuml;ğ&uuml;</strong></p>\r\n<p><strong>T&uuml;m HDMI\'larda bilgisayar girișleri:</strong>&nbsp;60 Hz\'de 4K UHD 3840x2160 değerine kadar, HDR destekli, HDR10/ HLG</p>\r\n<p><strong>T&uuml;m HDMI\'larda video girișleri:</strong>&nbsp;60 Hz\'de 4K UHD 3840x2160 değerine kadar, HDR destekli, HDR10/ HLG (Hybrid Log Gamma)</p>\r\n<p><strong>Smart TV &Ouml;zellikleri</strong></p>\r\n<p><strong>Kullanıcı Etkileșimi:</strong>&nbsp;SimplyShare, Ekran yansıtma</p>\r\n<p><strong>SmartTV uygulamaları:</strong>&nbsp;&Ccedil;evrimi&ccedil;i video mağazaları, A&ccedil;ık internet tarayıcı, Youtube, Netflix TV, İstek &uuml;zerine TV</p>\r\n<p><strong>Kurulum Kolaylığı:</strong>&nbsp;Philips cihazlarını otomatik algılama, Ağ kurulum sihirbazı, Ayarlar yardımcısı sihirbazı</p>\r\n<p><strong>Y&uuml;kseltilebilir bellenim:</strong>&nbsp;Otomatik bellenim y&uuml;kseltme sihirbazı, USB yoluyla y&uuml;kseltilebilir bellenim, &Ccedil;evrimi&ccedil;i bellenim y&uuml;kseltme</p>\r\n<p><strong>Kullanım Kolaylığı:</strong>&nbsp;Tek akıllı men&uuml; d&uuml;ğmesi, Ekran &uuml;zerinde kullanım kılavuzu</p>\r\n<p><strong>İșleme</strong></p>\r\n<p><strong>İșleme G&uuml;c&uuml;:</strong>&nbsp;&Ccedil;ift &Ccedil;ekirdekli</p>\r\n<p><strong>Tuner/Alım/İletim</strong></p>\r\n<p><strong>Dijital TV:</strong>&nbsp;DVB-T/T2/T2-HD/C/S/S2</p>\r\n<p><strong>Video Oynatma:</strong>&nbsp;PAL, SECAM</p>\r\n<p><strong>TV Program rehberi:</strong>&nbsp;8 g&uuml;nl&uuml;k Elektronik Program Rehberi</p>\r\n<p>Sinyal g&uuml;c&uuml; g&ouml;stergesi</p>\r\n<p><strong>Teletekst:</strong>&nbsp;1000 sayfa Yardımlı Metin</p>\r\n<p>HEVC desteği</p>\r\n<p><strong>G&uuml;&ccedil;</strong></p>\r\n<p><strong>Șebeke elektriği:</strong>&nbsp;AC 220 - 240 V 50/60 Hz</p>\r\n<p><strong>Bekleme modunda g&uuml;&ccedil; t&uuml;ketimi:</strong>&nbsp;&lt; 0,3 W</p>\r\n<p><strong>G&uuml;&ccedil; Tasarrufu &Ouml;zellikleri:</strong>&nbsp;Otomatik kapama zamanlayıcı, G&ouml;r&uuml;nt&uuml; dondurma (radyo i&ccedil;in)</p>\r\n<p>Ekonomik mod, Ișık sens&ouml;r&uuml;</p>\r\n<p><strong>Kapalı mod g&uuml;&ccedil; t&uuml;ketimi:</strong>&nbsp;Yok</p>\r\n<p><strong>Ses</strong></p>\r\n<p><strong>&Ccedil;ıkıș g&uuml;c&uuml; (RMS):</strong>&nbsp;20 W</p>\r\n<p><strong>Ses Geliștirme:</strong>&nbsp;A.I. Ses, Net Konușma Sesleri, Dolby Atmos, Gece modu, Dolby Bas G&uuml;&ccedil;lendirme, Yapay Zeka Destekli Ekolayzır</p>\r\n<p><strong>Hoparl&ouml;r yapılandırması:</strong>&nbsp;2 x 10 W tam aralıklı hoparl&ouml;r</p>\r\n<p><strong>Bağlantı</strong></p>\r\n<p><strong>HDMI bağlantı sayısı:</strong>&nbsp;3</p>\r\n<p><strong>USB sayısı:</strong>&nbsp;2</p>\r\n<p><strong>Kablosuz bağlantı:</strong>&nbsp;Wi-Fi 802.11n, 2x2, Tek bant</p>\r\n<p><strong>Diğer bağlantılar:</strong>&nbsp;Uydu Konekt&ouml;r&uuml;, Common Interface Plus (CI+), Dijital ses &ccedil;ıkıșı (optik), Ethernet-LAN RJ-45, Servis konekt&ouml;r&uuml;</p>\r\n<p><strong>HDMI &ouml;zellikleri:</strong>&nbsp;Ses D&ouml;n&uuml;ș Kanalı, 4K</p>\r\n<p><strong>EasyLink (HDMI-CEC):</strong>&nbsp;Uzaktan kumanda ge&ccedil;iși, Sistem ses kontrol&uuml;, Sistem bekleme, Tek dokunușla oynatma</p>\r\n<p><strong>HDCP 2.3:</strong>&nbsp;Evet, t&uuml;m HDMI\'larda</p>\r\n<p><strong>HDMI ARC:</strong>&nbsp;HDMI1\'de bulunur</p>\r\n<p><strong>HDMI 2.1 &ouml;zellikleri:</strong>&nbsp;HDMI 1 &uuml;zerinden eARC, EARC / VRR / ALLM desteklenir</p>\r\n<p><strong>Multimedya Uygulamaları</strong></p>\r\n<p><strong>Video Oynatma Formatları: A</strong>VI, MKV, H264/MPEG-4 AVC, MPEG-1, MPEG-2, MPEG-4, HEVC (H.265), VP9, AV1</p>\r\n<p><strong>Altyazı Formatları Desteği:</strong>&nbsp;.SMI, .SRT, .SUB, .TXT, .ASS, .SSA</p>\r\n<p><strong>M&uuml;zik &Ccedil;alma Formatları:</strong>&nbsp;AAC, MP3, WAV, WMA (v2 - v9.2 arası), WMA-PRO (v9 ve v10), FLAC</p>\r\n<p><strong>Fotoğraf G&ouml;r&uuml;nt&uuml;leme Formatları:</strong>&nbsp;JPEG, BMP, GIF, PNG, 360 fotoğraf, HEIF</p>\r\n<p><strong>Tasarım</strong></p>\r\n<p><strong>TV\'nin renkleri:</strong>&nbsp;Mat siyah &ccedil;er&ccedil;eve</p>\r\n<p><strong>Stand tasarımı:</strong>&nbsp;Mat siyah kesilmiș &ccedil;ubuklar</p>\r\n<p><strong>Boyutlar</strong></p>\r\n<p><strong>Kutu boyutları (G x Y x D):</strong>&nbsp;1100,0 x 680,0 x 140,0 mm</p>\r\n<p><strong>Set boyutları (G x Y x D):</strong>&nbsp;957,9 x 559,1 x 87,0 mm</p>\r\n<p><strong>Stand dahil boyutları ayarla (G x Y x D):</strong>&nbsp;957,9 x 587,2 x 218,3 mm</p>\r\n<p><strong>Sehpa boyutları (G x Y x D):</strong>&nbsp;753,7 x 28,0 x 218,6 mm</p>\r\n<p><strong>&Uuml;r&uuml;n ağırlığı:</strong>&nbsp;6,6 kg</p>\r\n<p><strong>&Uuml;r&uuml;n ağırlığı (+stand):</strong>&nbsp;6,7 kg</p>\r\n<p><strong>Ambalajla birlikte Ağırlık:</strong>&nbsp;9,3 kg</p>\r\n<p><strong>Duvara montaja uyumlu:</strong>&nbsp;200 x 100 mm</p>\r\n<p><strong>Aksesuarlar</strong></p>\r\n<p><strong>Birlikte verilen aksesuarlar:</strong></p>\r\n<p>Uzaktan Kumanda,</p>\r\n<p>2 x AAA Pil,</p>\r\n<p>G&uuml;&ccedil; kablosu,</p>\r\n<p>Hızlı bașlangı&ccedil; kılavuzu,</p>\r\n<p>Yasal bilgiler ve g&uuml;venlik broș&uuml;r&uuml;,</p>\r\n<p>Masa &uuml;st&uuml; stand</p>\r\n<p><strong>AB Enerji Kartı</strong></p>\r\n<p><strong>EPREL kayıt numaraları:</strong>&nbsp;<a href=\"tel:1198294\">1198294</a></p>\r\n<p><strong>SDR i&ccedil;in enerji sınıfı:</strong>&nbsp;F</p>\r\n<p><strong>SDR i&ccedil;in a&ccedil;ık mod g&uuml;&ccedil; talebi:</strong>&nbsp;51 Kwh/1000 sa</p>\r\n<p><strong>HDR i&ccedil;in enerji sınıfı:</strong>&nbsp;G</p>\r\n<p><strong>HDR i&ccedil;in a&ccedil;ık mod g&uuml;&ccedil; talebi:</strong>&nbsp;89 Kwh/1000 sa</p>\r\n<p><strong>Kapalı mod g&uuml;&ccedil; t&uuml;ketimi:</strong>&nbsp;ge&ccedil;ersiz</p>\r\n<p><strong>Kullanılan panel teknolojisi:</strong>&nbsp;LED LCD</p>\r\n<p><strong>Ağa bağlı bekleme modu:</strong>&nbsp;&lt;0,2 W</p>\r\n<p><strong>2 yıl Philips garantili</strong></p>\r\n<p>&Uuml;r&uuml;n&uuml;n garantisinin başlayabilmesi i&ccedil;in bu &uuml;r&uuml;n&uuml;n kutusu yetkili servis tarafından a&ccedil;ılmalı, kurulum yetkili servis tarafından yapılmalıdır.</p>\r\n<p><strong>Yetkili Servis Adı:&nbsp;</strong>PHILIPS Servis</p>\r\n<p><strong>Yetkili Servis İletişim Bilgisi:&nbsp;</strong><a href=\"tel:0850 222 44 66\">0850 222 44 66</a></p>\r\n<p>&nbsp;</p>\r\n<p>&Uuml;retim Yeri: &Ccedil;in</p>\r\n<p>İnternet sitemizde ve online satış kanallarımızda yer alan &uuml;r&uuml;n etiket bilgileri, &uuml;r&uuml;n&uuml;n tedarik&ccedil;isi tarafından A101 Yeni Mağazacılık A.Ş &lsquo;ye iletilen en g&uuml;ncel bilgilerdir. &Uuml;r&uuml;n etiket bilgileri ile internet sitemiz ve online satış kanallarımızda bulunan bilgiler arasında herhangi bir farklılık bulunması halinde sorumluluk tamamen tedarik&ccedil;i firmaya aittir.</p>\r\n<p>Fiyatlarımız; a101.com.tr, A101 Kapıda uygulaması ve mağazalarımızda farklılık g&ouml;sterebilir, belirtilen &uuml;r&uuml;n fiyatı yalnızca bu satış kanalı i&ccedil;in ge&ccedil;erlidir.</p>\r\n<p>&Uuml;r&uuml;nlerimiz, yukarıda belirtilen satış kanallarında satışa sunulmaktadır. Online satış kanalı, a101.com.tr website, mobil ve A101 uygulamasını kapsamaktadır.</p>\r\n<p>Mesafeli Satış S&ouml;zleşmemiz uyarınca; toptan veya yeniden satış ama&ccedil;lı oluşturulduğu tespit edilen siparişler ile &uuml;r&uuml;n, hizmet ve indirimlerimizden t&uuml;m m&uuml;şterilerimizin faydalanabilmesi ve stok&ccedil;uluğun engellenmesi i&ccedil;in 1 adetin &uuml;zerindeki doğrudan ve dolaylı siparişleri A101&rsquo;in iptal hakkı saklıdır.</p>', 'Philips', 26030738),
