(150, 'Apple iPhone 14 128 GB Cep Telefonu Mor', '165eb4df-42f0-4339-8c75-95dd79eb4a29_size780x780_quality60_cropCenter.jpg', '165eb4df-42f0-4339-8c75-95dd79eb4a29_size780x780_quality60_cropCenter.jpg', '165eb4df-42f0-4339-8c75-95dd79eb4a29_size780x780_quality60_cropCenter.jpg', '165eb4df-42f0-4339-8c75-95dd79eb4a29_size780x780_quality60_cropCenter.jpg', 'apple-iphone-14-128-gb-cep-telefonu-mor', 41299, '<p><strong>Apple iPhone 14 128 GB Cep Telefonu Mor</strong></p>\r\n\r\n<p><strong>Suya, Sıçramalara ve Toza Dayanıklılık</strong></p>\r\n\r\n<p>60529 sayılı IEC standardı kapsamında IP68 derecesi (30 dakikaya kadar maksimum 6 metre derinlik)</p>\r\n\r\n<p><strong>Çip</strong></p>\r\n\r\n<p>A15 Bionic çip</p>\r\n\r\n<p>2 adet performans çekirdeğine ve 4 adet verimlilik çekirdeğine sahip 6 çekirdekli CPU</p>\r\n\r\n<p>5 çekirdekli GPU</p>\r\n\r\n<p>16 çekirdekli Neural Engine</p>\r\n\r\n<p><strong>Kamera</strong></p>\r\n\r\n<p>Çift kamera sistemi</p>\r\n\r\n<p>12 MP Ana kamera: 26 mm, &fnof;/1.5 diyafram, sensör bazlı optik görüntü stabilizasyonu, yedi bileşenli lens, %100 Focus Pixels</p>\r\n\r\n<p>12 MP Ultra Geniş kamera: 13 mm, &fnof;/2.4 diyafram ve 120&deg; görüş alanı, beş bileşenli lens</p>\r\n\r\n<p>2 kat optik uzaklaştırma; 5 kata kadar dijital zoom</p>\r\n\r\n<p>Safir kristal lens kapağı</p>\r\n\r\n<p>True Tone Flash</p>\r\n\r\n<p>Photonic Engine</p>\r\n\r\n<p>Deep Fusion</p>\r\n\r\n<p>Akıllı HDR 4</p>\r\n\r\n<p>Gelişmiş bokeh efektine ve Derinlik Denetimi&rsquo;ne sahip Portre modu</p>\r\n\r\n<p>Altı efektli (Doğal, Stüdyo, Kontur, Sahne, Sahne Mono, High-Key Mono) Portre Işığı</p>\r\n\r\n<p>Gece modu</p>\r\n\r\n<p>Panorama (63 megapiksele kadar)</p>\r\n\r\n<p>Fotoğrafik Stiller</p>\r\n\r\n<p>Fotoğraflar ve Live Photo&rsquo;lar için geniş renk yelpazesiyle çekim</p>\r\n\r\n<p>Lens düzeltme (Ultra Geniş)</p>\r\n\r\n<p>Gelişmiş kırmızı göz düzeltme</p>\r\n\r\n<p>Otomatik görüntü stabilizasyonu</p>\r\n\r\n<p>Seri çekim modu</p>\r\n\r\n<p>Fotoğraflara konum bilgisi ekleme</p>\r\n\r\n<p>Çekilebilen görüntü biçimleri: HEIF ve JPEG</p>\r\n\r\n<p><strong>Video Kaydı</strong></p>\r\n\r\n<p>Saniyede 24, 25, 30 veya 60 kare 4K video kaydı</p>\r\n\r\n<p>Saniyede 25, 30 veya 60 kare 1080p HD video kaydı</p>\r\n\r\n<p>Saniyede 30 kare 720p HD video kaydı</p>\r\n\r\n<p>Saniyede 30 kare 4K HDR çözünürlüğe kadar Sinematik mod</p>\r\n\r\n<p>Saniyede 60 kare 2.8K çözünürlüğe kadar Hareket modu</p>\r\n\r\n<p>Dolby Vision ile saniyede 60 kareye kadar 4K HDR video kaydı</p>\r\n\r\n<p>Saniyede 120 veya 240 kare 1080p ağır çekim video desteği</p>\r\n\r\n<p>Stabilizasyon özelliğine sahip hızlı çekim video kaydı</p>\r\n\r\n<p>Gece modunda hızlı çekim</p>\r\n\r\n<p>QuickTake video</p>\r\n\r\n<p>Videolar için sensör bazlı optik görüntü stabilizasyonu (Ana kamera)</p>\r\n\r\n<p>2 kat optik uzaklaştırma</p>\r\n\r\n<p>3 kata kadar dijital zoom</p>\r\n\r\n<p>İşitsel zoom</p>\r\n\r\n<p>True Tone Flash</p>\r\n\r\n<p>Sinematik video stabilizasyonu (4K, 1080p ve 720p)</p>\r\n\r\n<p>Kesintisiz otomatik netleme özelliğine sahip video kaydı</p>\r\n\r\n<p>4K video kaydederken 8 MP fotoğraf çekme</p>\r\n\r\n<p>Videoyu oynatırken yakınlaştırma</p>\r\n\r\n<p>Kaydedilebilen video biçimleri: HEVC ve H.264</p>\r\n\r\n<p>Stereo kayıt</p>\r\n\r\n<p><strong>TrueDepth Kamera</strong></p>\r\n\r\n<p>12 MP kamera</p>\r\n\r\n<p>&fnof;/1.9 diyafram</p>\r\n\r\n<p>Focus Pixels özelliğine sahip otomatik netleme</p>\r\n\r\n<p>Altı bileşenli lens</p>\r\n\r\n<p>Retina Flash</p>\r\n\r\n<p>Photonic Engine</p>\r\n\r\n<p>Deep Fusion</p>\r\n\r\n<p>Akıllı HDR 4</p>\r\n\r\n<p>Gelişmiş bokeh efektine ve Derinlik Denetimi&rsquo;ne sahip Portre modu</p>\r\n\r\n<p>Altı efektli (Doğal, Stüdyo, Kontur, Sahne, Sahne Mono, High-Key Mono) Portre Işığı</p>\r\n\r\n<p>Animoji ve Memoji</p>\r\n\r\n<p>Gece modu</p>\r\n\r\n<p>Fotoğrafik Stiller</p>\r\n\r\n<p>Fotoğraflar ve Live Photo&rsquo;lar için geniş renk yelpazesiyle çekim</p>\r\n\r\n<p>Lens düzeltme</p>\r\n\r\n<p>Otomatik görüntü stabilizasyonu</p>\r\n\r\n<p>Seri çekim modu</p>\r\n\r\n<p>Saniyede 24, 25, 30 veya 60 kare 4K video kaydı</p>\r\n\r\n<p>Saniyede 25, 30 veya 60 kare 1080p HD video kaydı</p>\r\n\r\n<p>Saniyede 30 kare 4K HDR çözünürlüğe kadar Sinematik mod</p>\r\n\r\n<p>Dolby Vision ile saniyede 60 kareye kadar 4K HDR video kaydı</p>\r\n\r\n<p>Saniyede 120 kare 1080p ağır çekim video desteği</p>\r\n\r\n<p>Stabilizasyon özelliğine sahip hızlı çekim video kaydı</p>\r\n\r\n<p>Gece modunda hızlı çekim</p>\r\n\r\n<p>QuickTake video</p>\r\n\r\n<p>Sinematik video stabilizasyonu (4K, 1080p ve 720p)</p>\r\n\r\n<p><strong>Face ID</strong></p>\r\n\r\n<p>TrueDepth kamera aracılığıyla yüz tanıma</p>\r\n\r\n<p><strong>Güvenlik</strong></p>\r\n\r\n<p>Acil SOS</p>\r\n\r\n<p>Trafik Kazası Algılama</p>\r\n\r\n<p><strong>Cellular ve Wireless</strong></p>\r\n\r\n<p><strong>Tüm modeller</strong></p>\r\n\r\n<p>4x4 MIMO özellikli 5G (sub 6 GHz) 4</p>\r\n\r\n<p>4x4 MIMO ve LAA özelliklerine sahip Gigabit LTE4</p>\r\n\r\n<p>2x2 MIMO özellikli Wi Fi 6 (802.11ax)</p>\r\n\r\n<p>Bluetooth 5.3</p>\r\n\r\n<p>Uzamsal farkındalık için Ultra Geniş Bant çipi5</p>\r\n\r\n<p>Okuyucu modu özellikli NFC</p>\r\n\r\n<p>Güç koruma özellikli Ekspres Kartlar</p>\r\n\r\n<p><strong>Konum</strong></p>\r\n\r\n<p>GPS, GLONASS, Galileo, QZSS ve BeiDou</p>\r\n\r\n<p>Dijital pusula</p>\r\n\r\n<p>Wi-Fi</p>\r\n\r\n<p>Cellular</p>\r\n\r\n<p>iBeacon ile mikro lokasyon</p>\r\n\r\n<p><strong>Görüntülü Arama</strong></p>\r\n\r\n<p>Hücresel ağ veya Wi-Fi üzerinden FaceTime görüntülü arama</p>\r\n\r\n<p>5G veya Wi-Fi üzerinden FaceTime HD (1080p) görüntülü arama</p>\r\n\r\n<p>SharePlay ile bir FaceTime görüşmesindeyken film, TV programı, müzik veya diğer uygulama deneyimlerini paylaşma</p>\r\n\r\n<p>Ekran paylaşımı</p>\r\n\r\n<p>FaceTime görüntülü aramada Portre modu</p>\r\n\r\n<p>Uzamsal Ses</p>\r\n\r\n<p>Ses İzolasyonu ve Geniş Spektrum mikrofon modları</p>\r\n\r\n<p>Arka kamera ile zoom</p>\r\n\r\n<p><strong>Sesli Arama</strong></p>\r\n\r\n<p>FaceTime sesli arama</p>\r\n\r\n<p>Voice over LTE (VoLTE)</p>\r\n\r\n<p>Wi-Fi üzerinden arama</p>\r\n\r\n<p>SharePlay ile bir FaceTime görüşmesindeyken film, TV programı, müzik veya diğer uygulama deneyimlerini paylaşma</p>\r\n\r\n<p>Ekran paylaşımı</p>\r\n\r\n<p>Uzamsal Ses</p>\r\n\r\n<p>Ses İzolasyonu ve Geniş Spektrum mikrofon modları</p>\r\n\r\n<p><strong>Ses Çalma</strong></p>\r\n\r\n<p>Desteklenen biçimler arasında AAC, MP3, Apple Lossless, FLAC, Dolby Digital, Dolby Digital Plus ve Dolby Atmos yer alır</p>\r\n\r\n<p>Uzamsal Ses çalma</p>\r\n\r\n<p>Kullanıcı tarafından yapılandırılabilen maksimum ses düzeyi sınırı</p>\r\n\r\n<p><strong>Video Oynatma</strong></p>\r\n\r\n<p>Desteklenen biçimler arasında HEVC, H.264 ve ProRes yer alır</p>\r\n\r\n<p>Dolby Vision, HDR10 ve HLG özellikli HDR</p>\r\n\r\n<p>Apple TV&rsquo;ye (2. nesil veya daha yeni bir model) veya AirPlay 2 özellikli akıllı televizyonlara 4K HDR kalitesine kadar AirPlay yansıtma, fotoğraf ve video çıkışı</p>\r\n\r\n<p>Video yansıtma ve video çıkışı desteği: Lightning Dijital AV Adaptörü ve Lightning - VGA Adaptörü ile 1080p&rsquo;ye kadar (adaptörler ayrı satılır)</p>\r\n\r\n<p><strong>Siri</strong></p>\r\n\r\n<p>Mesaj göndermek, anımsatıcı ayarlamak ve çok daha fazlası için sesinizi kullanın</p>\r\n\r\n<p>&ldquo;Hey Siri&rdquo; özelliğiyle, ellerinizi kullanmadan sadece sesinizle etkinleştirin</p>\r\n\r\n<p>Favori uygulamalarınızda kestirmeleri çalıştırmak için sesinizi kullanın</p>\r\n\r\n<p><strong>Harici Düğmeler ve Konnektörler</strong></p>\r\n\r\n<p>Ses yükseltme/azaltma</p>\r\n\r\n<p>Zil/Sessiz</p>\r\n\r\n<p>Yan düğme</p>\r\n\r\n<p>Yerleşik stereo hoparlör</p>\r\n\r\n<p>Yerleşik mikrofon</p>\r\n\r\n<p>Lightning konnektörü</p>\r\n\r\n<p>Yerleşik mikrofonlar</p>\r\n\r\n<p>Yerleşik stereo hoparlör</p>\r\n\r\n<p><strong>Güç ve Pil</strong></p>\r\n\r\n<p><strong>Video oynatma:</strong>20 saate kadar</p>\r\n\r\n<p><strong>Online video oynatma:</strong>&nbsp;16 saate kadar</p>\r\n\r\n<p><strong>Ses çalma:</strong>&nbsp;80 saate kadar</p>\r\n\r\n<p><strong>Video oynatma:</strong>&nbsp;26 saate kadar</p>\r\n\r\n<p><strong>Online video oynatma:</strong>&nbsp;20 saate kadar</p>\r\n\r\n<p><strong>Ses çalma:</strong>&nbsp;100 saate kadar</p>\r\n\r\n<p><strong>İki modelde de:</strong></p>\r\n\r\n<p>Şarj edilebilir yerleşik lityum iyon pil</p>\r\n\r\n<p>15 W&rsquo;a kadar MagSafe özellikli kablosuz şarj</p>\r\n\r\n<p>7,5 W&rsquo;a kadar Qi özellikli kablosuz şarj11</p>\r\n\r\n<p>USB üzerinden bilgisayara veya güç adaptörüne bağlayarak şarj etme</p>\r\n\r\n<p><strong>Hızlı şarj özelliği</strong></p>\r\n\r\n<p>20 W veya daha güçlü bir adaptör ile yaklaşık 30 dakikada10 %50&rsquo;ye kadar şarj (adaptör ayrı satılır)</p>\r\n\r\n<p><strong>MagSafe</strong></p>\r\n\r\n<p>15 W&rsquo;a kadar kablosuz şarj</p>\r\n\r\n<p>Mıknatıs dizilimi</p>\r\n\r\n<p>Hizalama mıknatısı</p>\r\n\r\n<p>Aksesuar Tanıma özellikli NFC</p>\r\n\r\n<p>Manyetometre</p>\r\n\r\n<p><strong>Sensörler</strong></p>\r\n\r\n<p>Face ID</p>\r\n\r\n<p>Barometre</p>\r\n\r\n<p>Yüksek dinamik aralıklı jiroskop</p>\r\n\r\n<p>Yüksek g ivmeölçeri</p>\r\n\r\n<p>Yakınlık sensörü</p>\r\n\r\n<p>Çift ortam ışığı sensörü</p>\r\n\r\n<p><strong>İşletim Sistemi</strong></p>\r\n\r\n<p>iOS 16</p>\r\n\r\n<p><strong>Erişilebilirlik</strong></p>\r\n\r\n<p>Görme, hareket, işitme ve bilişsel engelleri olan kişilerin ihtiyaçlarına destek veren yerleşik erişilebilirlik özellikleri iPhone&rsquo;unuzdan en iyi şekilde yararlanmanıza yardımcı oluyor.</p>\r\n\r\n<p><strong>SIM Kart</strong></p>\r\n\r\n<p>Çift eSIM desteği12</p>\r\n\r\n<p>Çift SIM (nano SIM ve eSIM)</p>\r\n\r\n<p><strong>İşitme Cihazı Derecelendirmesi</strong></p>\r\n\r\n<p>M3, T4</p>\r\n', 'Apple', 26029309004),
