\r\n', 'Regal', 26017770),
(178, 'Microsoft XBox S Series Oyun Konsolu 512 GB Beyaz', 'b543f2fc-cc11-4285-a562-e7bb786efb9b_size780x780_quality60_cropCenter.jpg', 'b543f2fc-cc11-4285-a562-e7bb786efb9b_size780x780_quality60_cropCenter.jpg', 'b543f2fc-cc11-4285-a562-e7bb786efb9b_size780x780_quality60_cropCenter.jpg', 'b543f2fc-cc11-4285-a562-e7bb786efb9b_size780x780_quality60_cropCenter.jpg', 'microsoft-xbox-s-series-oyun-konsolu-512-gb-beyaz', 7499, '<p><strong>İŞLEMCİ</strong></p>\r\n<p>CPU. 3,6 GHz Hızında 8X &Ccedil;ekirdek (SMT ile 3,4 GHz) &Ouml;zel Zen 2 CPU<br /><br />GPU. 4 TFLOP, 1,565 GHz Hızında 20 CU &Ouml;zel RDNA 2 GPU<br /><br />SOC Yonga Boyutu. 197,05 mm2</p>\r\n<p><strong>BELLEK VE DEPOLAMA</strong></p>\r\n<p><strong>Bellek</strong>&nbsp;10 GB GDDR6 128 bit genişliğinde veri yolu<br /><br /><strong>Bellek Bant Genişliği</strong>&nbsp;224 GB/sn hızında 8GB, 56 GB/sn hızında 2GB.<br /><br /><strong>Dahili Depolama</strong>&nbsp;512 GB &Ouml;zel NVME SSD<br /><br /><strong>G/&Ccedil; Aktarım Hızı</strong>&nbsp;2,4 GB/sn (Ham), 4,8 GB/sn (Sıkıştırılmış, &ouml;zel donanım sıkıştırma a&ccedil;ma bloğuyla)<br /><br /><strong>Genişletilebilir Depolama</strong>&nbsp;Xbox Series X|S i&ccedil;in 1 TB Genişletme Kartı desteği, dahili depolama alanıyla tamamen eşleşir (ayrı olarak satılır). USB 3.1 harici HDD desteği (ayrı olarak satılır).</p>\r\n<p><strong>VİDEO &Ouml;ZELLİKLERİ</strong></p>\r\n<p><strong>Oyun &Ccedil;&ouml;z&uuml;n&uuml;rl&uuml;ğ&uuml;</strong>&nbsp;1440p<br /><br /><strong>Performans Hedefi&nbsp;</strong>120 FPS\'ye Kadar<br /><br /><strong>HDMI &Ouml;zellikleri</strong>&nbsp;Otomatik D&uuml;ş&uuml;k Gecikme Modu, HDMI Değişken Yenileme Hızı, AMD FreeSync.<br /><br /><strong>SES &Ouml;ZELLİKLERİ</strong></p>\r\n<p>L-PCM, 7.1\'e kadar<br /><br />Dolby Digital 5.1<br /><br />DTS 5.1<br /><br />Atmos ile Dolby TrueHD<br /><br /><strong>BAĞLANTI NOKTALARI VE BAĞLANTI</strong></p>\r\n<p><strong>HDMI</strong>&nbsp;1 adet HDMI 2.1 bağlantı noktası<br /><br /><strong>USB</strong>&nbsp;3 adet USB 3.1 Gen 1 bağlantı noktası<br /><br /><strong>Kablosuz</strong>&nbsp;802.11ac &ccedil;ift bant<br /><br /><strong>Ethernet</strong>&nbsp;802.3 10/100/1000</p>\r\n<p>1 adet oyun kolu mevcuttur</p>\r\n<p>&Ouml;zel &ccedil;ift bant Xbox Kablosuz radyo</p>\r\n<p><strong>&Uuml;r&uuml;n ile birlikte hediye oyun g&ouml;nderilmemektedir</strong></p>\r\n<p><strong>&Uuml;r&uuml;n 2 yıl Microsoft T&uuml;rkiye garantisi altındadır</strong></p>\r\n<p>&nbsp;</p>\r\n<p>&Uuml;retim Yeri: &Ccedil;in</p>\r\n<p>İnternet sitemizde ve online satış kanallarımızda yer alan &uuml;r&uuml;n etiket bilgileri, &uuml;r&uuml;n&uuml;n tedarik&ccedil;isi tarafından A101 Yeni Mağazacılık A.Ş &lsquo;ye iletilen en g&uuml;ncel bilgilerdir. &Uuml;r&uuml;n etiket bilgileri ile internet sitemiz ve online satış kanallarımızda bulunan bilgiler arasında herhangi bir farklılık bulunması halinde sorumluluk tamamen tedarik&ccedil;i firmaya aittir.</p>\r\n<p>Fiyatlarımız; a101.com.tr, A101 Kapıda uygulaması ve mağazalarımızda farklılık g&ouml;sterebilir, belirtilen &uuml;r&uuml;n fiyatı yalnızca bu satış kanalı i&ccedil;in ge&ccedil;erlidir.</p>\r\n<p>&Uuml;r&uuml;nlerimiz, yukarıda belirtilen satış kanallarında satışa sunulmaktadır. Online satış kanalı, a101.com.tr website, mobil ve A101 uygulamasını kapsamaktadır.</p>\r\n<p>Mesafeli Satış S&ouml;zleşmemiz uyarınca; toptan veya yeniden satış ama&ccedil;lı oluşturulduğu tespit edilen siparişler ile &uuml;r&uuml;n, hizmet ve indirimlerimizden t&uuml;m m&uuml;şterilerimizin faydalanabilmesi ve stok&ccedil;uluğun engellenmesi i&ccedil;in 2 adetin &uuml;zerindeki doğrudan ve dolaylı siparişleri A101&rsquo;in iptal hakkı saklıdır.</p>', 'Microsoft', 26020809),
(179, 'Sony Playstation 5 Digital Sürüm Oyun Konsolu', '143a9c5e-f014-4969-afbc-2051f06f8354_size780x780_quality60_cropCenter.jpg', '143a9c5e-f014-4969-afbc-2051f06f8354_size780x780_quality60_cropCenter.jpg', '143a9c5e-f014-4969-afbc-2051f06f8354_size780x780_quality60_cropCenter.jpg', '143a9c5e-f014-4969-afbc-2051f06f8354_size780x780_quality60_cropCenter.jpg', 'sony-playstation-5-digital-surum-oyun-konsolu', 10990, '<p><strong>Sony Playstation 5 Digital S&uuml;r&uuml;m Oyun Konsolu</strong></p>\r\n<p><strong>Dahili hafıza</strong></p>\r\n<p>825 GB SSD</p>\r\n<p><strong>Dahili hafıza tipi</strong></p>\r\n<p>SSD</p>\r\n<p><strong>İşlemci Markası</strong></p>\r\n<p>AMD</p>\r\n<p><strong>İşlemci Teknolojisi</strong></p>\r\n<p>AMD Zen 2</p>\r\n<p><strong>İşlemci Hızı</strong></p>\r\n<p>3.5GHZ</p>\r\n<p><strong>İşlemci &Ccedil;ekirdek Sayısı</strong></p>\r\n<p>8</p>\r\n<p><strong>Grafik işlemci</strong></p>\r\n<p>AMD RDNA 2</p>\r\n<p><strong>Grafik işlemci frekansı</strong></p>\r\n<p>120HZ</p>\r\n<p><strong>Video &Ccedil;&ouml;z&uuml;n&uuml;rl&uuml;ğ&uuml;</strong></p>\r\n<p>4K</p>\r\n<p><strong>Depolama ortamı</strong></p>\r\n<p>SSD</p>\r\n<p><strong>Dahili hafıza</strong></p>\r\n<p>825GB SSD</p>\r\n<p><strong>Ethernet LAN bağlantısı</strong></p>\r\n<p>Var</p>\r\n<p><strong>Wi-Fi</strong></p>\r\n<p>Var</p>\r\n<p><strong>Bluetooth</strong></p>\r\n<p>Var</p>\r\n<p><strong>HDMI port sayısı</strong></p>\r\n<p>1</p>\r\n<p><strong>HDMI versiyonu</strong></p>\r\n<p>HDM! 2.1</p>\r\n<p><strong>USB 3.2 Gen 1 (3.1 Gen 1) Tip-A port sayısı</strong></p>\r\n<p>1</p>\r\n<p><strong>Fiş i&ccedil;i DC</strong></p>\r\n<p>Avrupa</p>\r\n<p><strong>HD t&uuml;r&uuml;</strong></p>\r\n<p>4K</p>\r\n<p><strong>Ram (Sistem Belleği)</strong></p>\r\n<p>16 GB</p>\r\n<p><strong>Ram Tipi</strong></p>\r\n<p>GDDR6</p>\r\n<p><strong>Disk Kapasitesi</strong></p>\r\n<p>825GB SSD</p>\r\n<p><strong>Paket İ&ccedil;eriği</strong></p>\r\n<p>PS5 Dijital versiyon konsol + Dualsense oyuncu kolu+ G&uuml;&ccedil; &nbs